import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { adminAPI } from '../../services/api';
import PeopleIcon from '@mui/icons-material/People';
import ShoppingBagIcon from '@mui/icons-material/ShoppingBag';
import LocalCafeIcon from '@mui/icons-material/LocalCafe';
import AttachMoneyIcon from '@mui/icons-material/AttachMoney';
import WarningAmberIcon from '@mui/icons-material/WarningAmber';

const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

const StatCard = ({ icon, label, value, sub, color = 'tea' }) => (
  <div className="card p-5">
    <div className="flex items-start justify-between">
      <div>
        <p className="text-sm text-gray-500 mb-1">{label}</p>
        <p className="text-2xl font-bold text-gray-900">{value}</p>
        {sub && <p className="text-xs text-gray-400 mt-1">{sub}</p>}
      </div>
      <div className={`w-10 h-10 bg-${color}-100 rounded-xl flex items-center justify-center text-${color}-600`}>
        {icon}
      </div>
    </div>
  </div>
);

const AdminDashboard = () => {
  const [analytics, setAnalytics] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    adminAPI.getAnalytics()
      .then(({ data }) => setAnalytics(data.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  if (loading) return (
    <div className="p-8 grid grid-cols-2 lg:grid-cols-4 gap-5">
      {[...Array(4)].map((_, i) => <div key={i} className="h-28 bg-tea-100 rounded-2xl animate-pulse" />)}
    </div>
  );

  if (!analytics) return null;

  // Build bar chart from monthly data
  const maxRevenue = Math.max(...(analytics.monthlyRevenue?.map(m => m.revenue) || [1]));

  return (
    <div className="p-6 max-w-7xl mx-auto">
      <div className="flex items-center justify-between mb-8">
        <h1 className="font-display text-3xl text-tea-900">Dashboard</h1>
        <span className="text-sm text-gray-400">{new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</span>
      </div>

      {/* Stat Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-5 mb-8">
        <StatCard icon={<AttachMoneyIcon />} label="Total Revenue" value={`$${analytics.totalRevenue?.toFixed(2) || '0.00'}`} sub="Excluding cancelled" color="tea" />
        <StatCard icon={<ShoppingBagIcon />} label="Total Orders" value={analytics.totalOrders} sub={`${analytics.pendingOrders} pending`} color="blue" />
        <StatCard icon={<PeopleIcon />} label="Total Users" value={analytics.totalUsers} color="sage" />
        <StatCard icon={<LocalCafeIcon />} label="Active Products" value={analytics.totalProducts} sub={analytics.lowStockCount > 0 ? `⚠ ${analytics.lowStockCount} low stock` : 'All stocked'} color="amber" />
      </div>

      <div className="grid lg:grid-cols-3 gap-6">
        {/* Revenue Chart */}
        <div className="lg:col-span-2 card p-6">
          <h2 className="font-display text-lg text-tea-900 mb-5">Monthly Revenue</h2>
          {analytics.monthlyRevenue?.length > 0 ? (
            <div className="flex items-end gap-2 h-40">
              {analytics.monthlyRevenue.map((m, i) => {
                const height = Math.max(4, (m.revenue / maxRevenue) * 100);
                return (
                  <div key={i} className="flex-1 flex flex-col items-center gap-1.5 group">
                    <div className="relative w-full">
                      <div
                        className="w-full bg-tea-200 group-hover:bg-tea-400 rounded-t-md transition-colors cursor-default"
                        style={{ height: `${height * 1.4}px` }}
                        title={`$${m.revenue.toFixed(2)}`}
                      />
                    </div>
                    <span className="text-xs text-gray-400">{MONTHS[m._id.month - 1]}</span>
                  </div>
                );
              })}
            </div>
          ) : (
            <div className="h-40 flex items-center justify-center text-gray-400 text-sm">No revenue data yet</div>
          )}
        </div>

        {/* Top Products */}
        <div className="card p-6">
          <h2 className="font-display text-lg text-tea-900 mb-5">Top Products</h2>
          {analytics.topProducts?.length > 0 ? (
            <div className="space-y-3">
              {analytics.topProducts.map((p, i) => (
                <div key={p._id} className="flex items-center gap-3">
                  <span className="w-5 h-5 rounded-full bg-tea-100 text-tea-700 text-xs flex items-center justify-center font-bold">{i+1}</span>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-800 truncate">{p.name}</p>
                    <p className="text-xs text-gray-500">{p.totalSold} sold</p>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <p className="text-sm text-gray-400">No sales data yet</p>
          )}
        </div>
      </div>

      {/* Quick nav */}
      <div className="grid sm:grid-cols-3 gap-4 mt-6">
        {[
          { label: 'Manage Products', to: '/admin/products', icon: '🍵', desc: 'Add, edit or remove products' },
          { label: 'View All Orders', to: '/admin/orders', icon: '📦', desc: 'Update order statuses' },
          { label: 'Manage Users', to: '/admin/users', icon: '👥', desc: 'Block/unblock user accounts' },
        ].map((item) => (
          <Link key={item.to} to={item.to} className="card p-5 hover:shadow-md transition-shadow flex items-start gap-4">
            <span className="text-2xl">{item.icon}</span>
            <div>
              <p className="font-semibold text-gray-800 text-sm">{item.label}</p>
              <p className="text-xs text-gray-500 mt-0.5">{item.desc}</p>
            </div>
          </Link>
        ))}
      </div>
    </div>
  );
};

export default AdminDashboard;
